// ── BRANDS ──────────────────────────────────────────────────────
const brands = [
  {name:'KRAFT HEINZ',img:'data:image/png;base64,'},
  {name:'ELI LILLY',img:'data:image/png;base64,'},
  {name:'PFIZER',img:null},
  {name:'JOHNSON & JOHNSON',img:'data:image/png;base64,'},
  {name:'DISNEY',img:'data:image/png;base64,'},
  {name:'VIACOM',img:null},
  {name:'ALTEC LANSING',img:'data:image/png;base64,'},
  {name:'MLBPA',img:null},
  {name:'NY YANKEES',img:'data:image/png;base64,'},
  {name:'MESA/BOOGIE',img:null},
  {name:'LE TIGRE',img:'data:image/webp;base64,'},
  {name:'SIGIL',img:'data:image/png;base64,'},
  {name:'LAS VEGAS RAIDERS',img:null},
  {name:'GREENWICH FILM FESTIVAL',img:null},
  {name:'SCANDALOUS',img:null}
];

function buildTicker(id) {
  const el = document.getElementById(id);
  if (!el) return;
  let html = '';
  brands.forEach(b => {
    if (b.img) {
      html += `<div class="ticker-logo"><img src="${b.img}" alt="${b.name}" style="height:22px;max-width:120px;object-fit:contain;filter:brightness(0) invert(1);opacity:1"></div><div class="ticker-sep"></div>`;
    } else {
      html += `<div class="ticker-logo"><span class="ticker-logo-text">${b.name}</span></div><div class="ticker-sep"></div>`;
    }
  });
  el.innerHTML = html;
}
buildTicker('ticker1'); buildTicker('ticker2');
buildTicker('ticker3'); buildTicker('ticker4');

// ── NAVIGATION ───────────────────────────────────────────────────
let currentPage = 'home';

function nav(pageId) {
  document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
  document.querySelectorAll('.nav-item[data-page]').forEach(n => n.classList.remove('active'));
  const page = document.getElementById('page-' + pageId);
  if (page) { page.classList.add('active'); page.scrollTop = 0; }
  document.querySelector('.main').scrollTo(0, 0);
  const navEl = document.querySelector(`.nav-item[data-page="${pageId}"]`);
  if (navEl) navEl.classList.add('active');
  currentPage = pageId;
}

function openCase(slug) {
  document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
  document.querySelectorAll('.nav-item[data-page]').forEach(n => n.classList.remove('active'));
  const page = document.getElementById('page-case-' + slug);
  if (page) page.classList.add('active');
  document.querySelector('.main').scrollTo(0, 0);
  const navEl = document.querySelector('.nav-item[data-page="work"]');
  if (navEl) navEl.classList.add('active');
}

// Keyboard shortcuts 1–9
document.addEventListener('keydown', e => {
  if (e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA') return;
  const pages = ['home','about','work','websites','media','writing','tools'];
  const n = parseInt(e.key);
  if (n >= 1 && n <= 7) nav(pages[n-1]);
  if (e.key === '8') nav('tools');
  if (e.key === '9') openModal();
  if (e.key === 'Escape') closeModal();
});

// ── WORK FILTER ──────────────────────────────────────────────────
function filterWork(btn, tag) {
  document.querySelectorAll('.filter-pill').forEach(p => p.classList.remove('active'));
  btn.classList.add('active');
  document.querySelectorAll('.work-card[data-tags]').forEach(card => {
    if (tag === 'all') { card.style.display = ''; return; }
    const tags = card.dataset.tags || '';
    card.style.display = tags.includes(tag) ? '' : 'none';
  });
}

// ── TOOLS FILTER ─────────────────────────────────────────────────
function filterTools(btn, cat) {
  btn.closest('.filter-bar').querySelectorAll('.filter-pill').forEach(p => p.classList.remove('active'));
  btn.classList.add('active');
  document.querySelectorAll('.tool-card[data-cat]').forEach(card => {
    if (cat === 'all') { card.style.display = ''; return; }
    const cats = card.dataset.cat || '';
    card.style.display = cats.includes(cat) ? '' : 'none';
  });
}

// ── CAR STEPS ────────────────────────────────────────────────────
function switchCar(btn, contentId) {
  const parent = btn.closest('.car-grid');
  parent.querySelectorAll('.car-step').forEach(s => s.classList.remove('active'));
  btn.classList.add('active');
  parent.querySelectorAll('.car-content').forEach(c => c.style.display = 'none');
  const el = document.getElementById(contentId);
  if (el) el.style.display = 'block';
}

// ── MODAL ────────────────────────────────────────────────────────
function openModal() {
  document.getElementById('modal-overlay').classList.add('open');
}
function closeModal() {
  document.getElementById('modal-overlay').classList.remove('open');
}
function handleOverlay(e) {
  if (e.target === document.getElementById('modal-overlay')) closeModal();
}
function toggleChip(el) { el.classList.toggle('selected'); }

// ── TIME ─────────────────────────────────────────────────────────
function updateTimes() {
  const et = new Date(new Date().toLocaleString('en-US', {timeZone:'America/New_York'}));
  let h = et.getHours(), m = et.getMinutes(), ampm = h >= 12 ? 'PM' : 'AM';
  h = h % 12 || 12;
  const t = h + ':' + String(m).padStart(2,'0') + ' ' + ampm;
  const el = document.getElementById('about-time');
  if (el) el.textContent = t;
}
updateTimes();
setInterval(updateTimes, 30000);

// ── THEME SWITCHER ───────────────────────────────────────────
function setTheme(t) {
  ['light','auto','dark'].forEach(x => {
    const b = document.getElementById('btn-'+x);
    if (b) b.classList.toggle('on', x === t);
  });
  if (t === 'dark') {
    document.documentElement.style.setProperty('--bg','#1a1917');
    document.documentElement.style.setProperty('--bg2','#232320');
    document.documentElement.style.setProperty('--bg3','#2e2c28');
    document.documentElement.style.setProperty('--border','#2e2c28');
    document.documentElement.style.setProperty('--border2','#3a3834');
    document.documentElement.style.setProperty('--text','#f0ede8');
    document.documentElement.style.setProperty('--text2','#a09c94');
    document.documentElement.style.setProperty('--text3','#5a5852');
  } else {
    document.documentElement.style.setProperty('--bg','#fafaf8');
    document.documentElement.style.setProperty('--bg2','#f2f0eb');
    document.documentElement.style.setProperty('--bg3','#e8e5de');
    document.documentElement.style.setProperty('--border','#d8d5ce');
    document.documentElement.style.setProperty('--border2','#c8c4bb');
    document.documentElement.style.setProperty('--text','#1a1917');
    document.documentElement.style.setProperty('--text2','#5a5852');
    document.documentElement.style.setProperty('--text3','#9a968e');
  }
}

function copyEmail() {
  navigator.clipboard.writeText('hello@michaelhnath.com').then(() => {
    const btn = event.target;
    const orig = btn.textContent;
    btn.textContent = 'Copied ✓';
    setTimeout(() => btn.textContent = orig, 1800);
  });
}